const triggerName = $prevNode.name;
const body = $input.all()[0].json;
return [{ json: { triggerName, body } }];

const body = $json.body;
const callStatus = (body.CallStatus || body.callstatus || '').toLowerCase();
const isMissedCall = ['no-answer','busy','failed'].includes(callStatus);
const toNumber = body.To || body.to || '';
const fromNumber = body.From || body.from || '';
return [{ json: { isMissedCall, callStatus, toNumber, fromNumber, body } }];

const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
const toNumber = $json.toNumber;
const { data: shop, error } = await supabase.from('shops').select('id,plan,status,monthly_limit,trial_ends_at,trial_conversation_limit,timezone,twilio_subaccount_sid,twilio_auth_token_enc,twilio_number,google_calendar_id,name').eq('twilio_number', toNumber).single();
if (error || !shop) throw new Error('Shop not found for number: ' + toNumber);
return [{ json: { shop, toNumber, fromNumber: $json.fromNumber } }];

const crypto = require('crypto');
const twilio = require('twilio');
const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
const { shop, fromNumber } = $json;

function decrypt(enc) {
  const [ivHex, dataHex] = enc.split(':');
  const iv = Buffer.from(ivHex, 'hex');
  const decipher = crypto.createDecipheriv('aes-256-cbc', Buffer.from(process.env.ENCRYPTION_KEY, 'hex'), iv);
  return Buffer.concat([decipher.update(Buffer.from(dataHex, 'hex')), decipher.final()]).toString('utf8');
}

if (shop.status === 'blocked') return [{ json: { skipped: true, reason: 'blocked' } }];

const { data: optOut } = await supabase.from('opt_outs').select('id').eq('shop_id', shop.id).eq('phone_number', fromNumber).maybeSingle();
if (optOut) return [{ json: { skipped: true, reason: 'opted_out' } }];

if (shop.plan === 'trial') {
  if (new Date() > new Date(shop.trial_ends_at)) return [{ json: { skipped: true, reason: 'trial_expired' } }];
  const { count } = await supabase.from('conversations').select('id', { count: 'exact', head: true }).eq('shop_id', shop.id).eq('counted', true);
  if (count >= shop.trial_conversation_limit) return [{ json: { skipped: true, reason: 'trial_limit' } }];
}

const { data: existing } = await supabase.from('conversations').select('id').eq('shop_id', shop.id).eq('customer_phone', fromNumber).eq('status', 'open').maybeSingle();
if (existing) return [{ json: { skipped: true, reason: 'already_open' } }];

const { data: conv } = await supabase.from('conversations').insert({ shop_id: shop.id, customer_phone: fromNumber, status: 'open', counted: true }).select().single();
const yearMonth = new Date().toISOString().substring(0, 7);
await supabase.rpc('increment_usage', { p_shop_id: shop.id, p_year_month: yearMonth });

const subToken = decrypt(shop.twilio_auth_token_enc);
const client = twilio(shop.twilio_subaccount_sid, subToken);
const body = `Hi! We missed your call at ${shop.name}. We'd love to help schedule your vehicle service. What can we help you with? Reply STOP to opt out.`;
const msg = await client.messages.create({ from: shop.twilio_number, to: fromNumber, body: body.substring(0, 320) });
await supabase.from('messages').insert({ conversation_id: conv.id, shop_id: shop.id, direction: 'outbound', body, twilio_sid: msg.sid });

return [{ json: { success: true, convId: conv.id } }];

const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
const body = $json.body;
const toNumber = body.To || body.to || '';
const fromNumber = body.From || body.from || '';
const inboundBody = body.Body || body.body || '';
const { data: shop, error } = await supabase.from('shops').select('id,plan,status,monthly_limit,trial_ends_at,trial_conversation_limit,timezone,twilio_subaccount_sid,twilio_auth_token_enc,twilio_number,google_calendar_id,name').eq('twilio_number', toNumber).single();
if (error || !shop) throw new Error('Shop not found: ' + toNumber);
return [{ json: { shop, toNumber, fromNumber, inboundBody } }];

const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
const { shop, fromNumber, inboundBody } = $json;

if (shop.status === 'blocked') return [{ json: { blocked: true, reason: 'account_blocked', shop, fromNumber, inboundBody } }];

const { data: optOut } = await supabase.from('opt_outs').select('id').eq('shop_id', shop.id).eq('phone_number', fromNumber).maybeSingle();
const upper = (inboundBody || '').toUpperCase().trim();

if (['STOP','STOPALL','UNSUBSCRIBE','CANCEL','END','QUIT'].includes(upper)) {
  await supabase.from('opt_outs').upsert({ shop_id: shop.id, phone_number: fromNumber }, { onConflict: 'shop_id,phone_number' });
  await supabase.from('conversations').update({ status: 'opted_out', ended_at: new Date().toISOString() }).eq('shop_id', shop.id).eq('customer_phone', fromNumber).eq('status', 'open');
  return [{ json: { blocked: true, reason: 'stop_received', shop, fromNumber, inboundBody } }];
}

if (optOut) {
  if (upper === 'START') {
    await supabase.from('opt_outs').delete().eq('shop_id', shop.id).eq('phone_number', fromNumber);
    return [{ json: { blocked: false, shop, fromNumber, inboundBody } }];
  }
  return [{ json: { blocked: true, reason: 'opted_out', shop, fromNumber, inboundBody } }];
}

if (shop.plan === 'trial') {
  if (new Date() > new Date(shop.trial_ends_at)) return [{ json: { blocked: true, reason: 'trial_expired', shop, fromNumber, inboundBody } }];
  const { data: openConv } = await supabase.from('conversations').select('id').eq('shop_id', shop.id).eq('customer_phone', fromNumber).eq('status', 'open').maybeSingle();
  if (!openConv) {
    const { count } = await supabase.from('conversations').select('id', { count: 'exact', head: true }).eq('shop_id', shop.id).eq('counted', true);
    if (count >= shop.trial_conversation_limit) return [{ json: { blocked: true, reason: 'trial_limit', shop, fromNumber, inboundBody } }];
  }
}

let softLimitWarning = null;
if (shop.plan !== 'trial') {
  const yearMonth = new Date().toISOString().substring(0, 7);
  const { data: usage } = await supabase.from('usage_monthly').select('conversations_used,warning_80_sent,warning_100_sent').eq('shop_id', shop.id).eq('year_month', yearMonth).maybeSingle();
  if (usage) {
    const pct = usage.conversations_used / shop.monthly_limit;
    if (pct >= 1.0 && !usage.warning_100_sent) softLimitWarning = '100';
    else if (pct >= 0.8 && !usage.warning_80_sent) softLimitWarning = '80';
  }
}

return [{ json: { blocked: false, shop, fromNumber, inboundBody, softLimitWarning } }];

const crypto = require('crypto');
const twilio = require('twilio');
const { reason, shop, fromNumber } = $json;

function decrypt(enc) {
  const [ivHex, dataHex] = enc.split(':');
  const iv = Buffer.from(ivHex, 'hex');
  const decipher = crypto.createDecipheriv('aes-256-cbc', Buffer.from(process.env.ENCRYPTION_KEY, 'hex'), iv);
  return Buffer.concat([decipher.update(Buffer.from(dataHex, 'hex')), decipher.final()]).toString('utf8');
}

if (reason === 'stop_received') {
  const subToken = decrypt(shop.twilio_auth_token_enc);
  const client = twilio(shop.twilio_subaccount_sid, subToken);
  await client.messages.create({ from: shop.twilio_number, to: fromNumber, body: 'You have been unsubscribed. Reply START to resubscribe. No further messages will be sent.' });
}

return [{ json: { done: true, reason } }];

const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
const { shop, fromNumber, inboundBody, softLimitWarning } = $json;

let { data: conv } = await supabase.from('conversations').select('id,counted,status').eq('shop_id', shop.id).eq('customer_phone', fromNumber).eq('status', 'open').maybeSingle();

if (!conv) {
  const { data: newConv } = await supabase.from('conversations').insert({ shop_id: shop.id, customer_phone: fromNumber, status: 'open', counted: false }).select().single();
  conv = newConv;
}

if (!conv.counted) {
  await supabase.from('conversations').update({ counted: true }).eq('id', conv.id);
  const yearMonth = new Date().toISOString().substring(0, 7);
  await supabase.rpc('increment_usage', { p_shop_id: shop.id, p_year_month: yearMonth });
}

await supabase.from('conversations').update({ last_activity_at: new Date().toISOString() }).eq('id', conv.id);
await supabase.from('messages').insert({ conversation_id: conv.id, shop_id: shop.id, direction: 'inbound', body: inboundBody });

const { data: history } = await supabase.from('messages').select('direction,body,sent_at').eq('conversation_id', conv.id).order('sent_at', { ascending: true }).limit(20);

if (softLimitWarning) {
  const yearMonth = new Date().toISOString().substring(0, 7);
  if (softLimitWarning === '80') await supabase.from('usage_monthly').update({ warning_80_sent: true }).eq('shop_id', shop.id).eq('year_month', yearMonth);
  if (softLimitWarning === '100') await supabase.from('usage_monthly').update({ warning_100_sent: true }).eq('shop_id', shop.id).eq('year_month', yearMonth);
}

return [{ json: { shop, fromNumber, inboundBody, conv, history: history || [], softLimitWarning } }];

const { shop, fromNumber, inboundBody, history } = $json;

const systemPrompt = `You are an AI appointment assistant for ${shop.name}, an auto repair shop in Texas. You communicate ONLY via SMS.\n\nRULES:\n1. Respond ONLY with valid JSON. No preamble, no markdown.\n2. reply field must be max 320 chars.\n3. Be warm, professional, concise.\n4. Collect in order: customer name, service needed, vehicle (year/make/model), preferred date/time.\n5. If you have all info, set nextAction to propose_slots or book.\n6. Never invent availability.\n\nOUTPUT SCHEMA (return ONLY this JSON):\n{\n  \"intent\": \"book|question|reschedule|cancel|handoff|unknown\",\n  \"customerName\": null,\n  \"serviceRequest\": null,\n  \"vehicle\": {\"year\": null, \"make\": null, \"model\": null},\n  \"preferred\": {\"date\": null, \"timeWindow\": null},\n  \"needs\": [],\n  \"nextAction\": \"ask|propose_slots|book|handoff\",\n  \"reply\": \"string max 320 chars\"\n}`;

const messages = (history || []).map(m => ({ role: m.direction === 'inbound' ? 'user' : 'assistant', content: m.body }));
if (!messages.length || messages[messages.length - 1].role !== 'user') {
  messages.push({ role: 'user', content: inboundBody });
}

const response = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01' },
  body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 512, system: systemPrompt, messages })
});

const data = await response.json();
const raw = data.content?.[0]?.text || '{}';

let parsed;
try { parsed = JSON.parse(raw); } catch (e) {
  parsed = { intent: 'unknown', customerName: null, serviceRequest: null, vehicle: { year: null, make: null, model: null }, preferred: { date: null, timeWindow: null }, needs: [], nextAction: 'ask', reply: "Thanks for reaching out! How can we help with your vehicle today?" };
}

return [{ json: { ...($json), claudeResponse: parsed } }];

const { createClient } = require('@supabase/supabase-js');
const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
const { shop, fromNumber, conv, claudeResponse } = $json;

const scheduledAt = new Date();
scheduledAt.setDate(scheduledAt.getDate() + 1);
scheduledAt.setHours(9, 0, 0, 0);

const windowStart = new Date(scheduledAt.getTime() - 30 * 60000).toISOString();
const windowEnd = new Date(scheduledAt.getTime() + 30 * 60000).toISOString();
const { data: existing } = await supabase.from('bookings').select('id').eq('shop_id', shop.id).gte('scheduled_at', windowStart).lte('scheduled_at', windowEnd).eq('status', 'confirmed').maybeSingle();

if (existing) {
  return [{ json: { ...$json, bookingConflict: true, claudeResponse: { ...claudeResponse, reply: "Sorry, that slot is taken. What other time works for you?", nextAction: 'ask' } } }];
}

let googleEventId = null;
try {
  const { google } = require('googleapis');
  const auth = new google.auth.OAuth2(process.env.GOOGLE_CLIENT_ID, process.env.GOOGLE_CLIENT_SECRET);
  auth.setCredentials({ refresh_token: process.env.GOOGLE_REFRESH_TOKEN });
  const calendar = google.calendar({ version: 'v3', auth });
  const event = await calendar.events.insert({
    calendarId: shop.google_calendar_id || 'primary',
    requestBody: {
      summary: `AutoShop: ${claudeResponse.serviceRequest || 'Service'} - ${claudeResponse.customerName || fromNumber}`,
      description: `Vehicle: ${claudeResponse.vehicle?.year || ''} ${claudeResponse.vehicle?.make || ''} ${claudeResponse.vehicle?.model || ''}\nPhone: ${fromNumber}`,
      start: { dateTime: scheduledAt.toISOString(), timeZone: shop.timezone },
      end: { dateTime: new Date(scheduledAt.getTime() + 3600000).toISOString(), timeZone: shop.timezone }
    }
  });
  googleEventId = event.data.id;
} catch (e) { console.error('Calendar error:', e.message); }

const { data: booking } = await supabase.from('bookings').insert({
  conversation_id: conv.id, shop_id: shop.id, customer_phone: fromNumber,
  customer_name: claudeResponse.customerName, service_request: claudeResponse.serviceRequest,
  vehicle_year: claudeResponse.vehicle?.year, vehicle_make: claudeResponse.vehicle?.make,
  vehicle_model: claudeResponse.vehicle?.model, scheduled_at: scheduledAt.toISOString(),
  google_event_id: googleEventId, status: 'confirmed'
}).select().single();

await supabase.from('conversations').update({ status: 'booked', ended_at: new Date().toISOString() }).eq('id', conv.id);

return [{ json: { ...$json, booking, bookingConflict: false } }];

